const fs = require('fs');
const path = require('path');

const validFileTypes = ['org', 'md', 'markdown', 'txt', 'html', 'xml', 'pdf', 'jpg', 'jpeg', 'png', 'webp'];

function isSupportedFileType(filePath) {
  const fileExtension = filePath.split('.').pop().toLowerCase();
  return validFileTypes.includes(fileExtension);
}

function processDirectory(filesToPush, folderPath) {
  try {
    const files = fs.readdirSync(folderPath, { withFileTypes: true });
    for (const file of files) {
      if (file.name.startsWith('.')) continue;
      const filePath = path.join(folderPath, file.name);
      if (file.isFile() && isSupportedFileType(filePath)) {
        filesToPush.push(filePath);
      }
      if (file.isDirectory()) {
        processDirectory(filesToPush, filePath);
      }
    }
  } catch (err) {
    console.error(`Error processing directory ${folderPath}:`, err.message);
  }
}

const filesToIndex = [];
const configuredFiles = $input.all()[0].body.files || [];
const configuredFolders = $input.all()[0].body.folders || [];

for (const file of configuredFiles) {
  if (fs.existsSync(file.path)) {
    filesToIndex.push(file.path);
  }
}

for (const folder of configuredFolders) {
  if (fs.existsSync(folder.path)) {
    processDirectory(filesToIndex, folder.path);
  }
}

return [{ json: { files: filesToIndex } }];

const fs = require('fs');

const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const filesData = [];

for (const filePath of $input.all()[0].json.files) {
  try {
    const stats = fs.statSync(filePath);
    const extension = filePath.split('.').pop().toLowerCase();
    const isBinary = binaryFileTypes.includes(extension);
    const encoding = isBinary ? 'binary' : 'utf8';
    const content = fs.readFileSync(filePath, { encoding });

    filesData.push({
      path: filePath,
      content: content.toString('base64'),
      mimeType: getMimeType(extension, encoding),
      modified: stats.mtime.toISOString()
    });
  } catch (err) {
    console.error(`Error reading file ${filePath}:`, err.message);
  }
}

function getMimeType(ext, encoding) {
  const types = {
    'pdf': 'application/pdf',
    'png': 'image/png',
    'jpg': 'image/jpeg',
    'jpeg': 'image/jpeg',
    'webp': 'image/webp',
    'md': 'text/markdown',
    'markdown': 'text/markdown',
    'org': 'text/org'
  };
  return (types[ext] || 'text/plain') + (encoding === 'utf8' ? '; charset=UTF-8' : '');
}

return [{ json: { filesData } }];

const syncResult = $input.all()[0].json;
const timestamp = new Date().toISOString();

return [{
  json: {
    status: 'completed',
    timestamp: timestamp,
    filesProcessed: syncResult.filesData ? syncResult.filesData.length : 0,
    syncedAt: timestamp
  }
}];

const error = $input.all()[0].json;
const timestamp = new Date().toISOString();

let errorMessage = 'Sync was unsuccessful';

if (error.response?.status === 429) {
  errorMessage = 'Out of space. Please upgrade your plan.';
} else if (error.code === 'ECONNREFUSED') {
  errorMessage = `Could not connect to Khoj server at ${error.address}:${error.port}`;
}

return [{
  json: {
    status: 'error',
    error: errorMessage,
    timestamp: timestamp
  }
}];
